{"query":"
      query GetTransactionByTokenForWallet($walletAddress: String, $tokenAddress: String, $offset: Int, $blockchainEnvironment: BlockchainEnvironment, $transactionOriginTypeFilter: String) {
  getTransactionByTokenForWallet(walletAddress: $walletAddress, tokenAddress: $tokenAddress, offset: $offset, blockchainEnvironment: $blockchainEnvironment, transactionOriginTypeFilter: $transactionOriginTypeFilter) {
    transactions {
      transactionBasicInfo {
        senderAddress
        receiverAddress
        transferAmount
        confirmationTime
        gasSUPRA
        transactionHash
        transactionStatus
        confirmationCount
        type
        functionName
        receivers {
          walletAddress        
        }
        senders {
          walletAddress        
        }
        transferDetails {
          tokenAddress
          tickerSymbol
          tokenName
          amount
          isDualNature
          from {
            walletAddress    
            isSpecialAddress
            isContractAddress   
          }
          to {
            walletAddress
            isSpecialAddress
            isContractAddress
          }

        }
        transferFADetails {
          tokenAddress
          symbol
          tokenName
          amount         
          isDualNature
          from {
            walletAddress        
            isSpecialAddress
            isContractAddress
          }
          to {
            walletAddress
            isSpecialAddress
            isContractAddress
          }
        }
        isMultipleTransfer
        transactionOriginType
        automationRegistryTxHash
        automationTaskId
        isRegisteringAutomation
        feePayerAddress
        vmType
      }
      transactionAdvancedInfo {    
        expirationTimeInSeconds    
        vmStatus
        payload
        output
        gasUnitPrice
        chainId
      }     
    }
    pageNumber
    pageCount
    totalItems
    isError
    errorType
    nextPage
    foundCount
  }
}
